30	func (a *scriptedAdapter) bundled(t *testing.T) *adapter.BundledAdapter {
31		t.Helper()
32		return &adapter.BundledAdapter{
33			Manifest: adapter.AdapterManifest{
34				Name:            a.name,
35				ContractVersion: adapter.ContractVersionV1,
36				Command:         []string{a.name + "-bundled"},
37			},
38			Run: func(ctx context.Context, stdin io.Reader, stdout io.Writer) error {
39				fr := contract.NewFrameReader(stdin)
40				for {
41					if err := ctx.Err(); err != nil {
42						return err
43					}
44					frame, err := fr.Read(contract.DefaultMaxFrameBytes)
45					if errors.Is(err, io.EOF) || errors.Is(err, io.ErrClosedPipe) {
46						return nil
47					}
48					if err != nil {
49						return err
50					}
51					msg, err := contract.ParseMessage(frame)
52					if err != nil {
53						return err
54					}
55					switch msg.Kind {
56					case contract.MessageKindNotification:
57						// swallow
58					case contract.MessageKindRequest:
59						resp := a.respond(msg)
60						out, err := json.Marshal(resp)
61						if err != nil {
62							return err
63						}
64						if err := contract.WriteFrame(stdout, out); err != nil {
65							return err
66						}
67					default:
68						return errors.New("scripted: unexpected message kind")
69					}
70				}
71			},
72		}
73	}
74	
75	func (a *scriptedAdapter) respond(req contract.Message) contract.Response {
