1	package claude
2	
3	import (
4		"cmp"
5		"context"
6		"encoding/json"
7		"fmt"
8		"slices"
9	
10		"github.com/agent-sync/agent-sync/internal/ir"
11		"github.com/agent-sync/agent-sync/pkg/adapterkit"
12	)
13	
14	// irNode is the wire-side shape of one IR node delivered via
15	// EmitParams.IR. The adapter does not import internal/ir's Node
16	// directly because that type carries decoder-internal fields the
17	// wire payload doesn't include.
18	type irNode struct {
19		ID         string          `json:"id"`
20		Kind       string          `json:"kind"`
21		Version    int             `json:"version,omitempty"`
22		Required   bool            `json:"required,omitempty"`
23		Targets    []string        `json:"targets,omitempty"`
24		Provenance irProvenance    `json:"provenance,omitempty"`
25		Body       json.RawMessage `json:"body,omitempty"`
26		Assets     []irAsset       `json:"assets,omitempty"`
27	}
28	
29	type irProvenance struct {
30		Path    string `json:"path,omitempty"`
31		BlobSHA string `json:"blob_sha,omitempty"`
32	}
33	
34	type irAsset struct {
35		RelPath    string          `json:"rel_path"`
36		Provenance irProvenance    `json:"provenance,omitempty"`
37		Content    json.RawMessage `json:"content,omitempty"`
38	}
39	
40	type irDocument struct {
41		Nodes []irNode `json:"nodes"`
42	}
43	
44	// emittedOps accumulates the ops a single emit call produces. Built
45	// up across kind-specific helpers; rendered into OpsPerformed at the
46	// end of handleEmit.
47	type emittedOps struct {
48		ops []adapterkit.Op
49	}
50	
51	func (e *emittedOps) add(op adapterkit.Op) {
52		e.ops = append(e.ops, op)
53	}
54	
55	// records returns the OpRecord summary slice the v1 protocol carries
56	// in EmitResult.OpsPerformed — the {kind, path} pairs the runtime's
57	// declared-outputs and capability-lied gates run against.
58	func (e *emittedOps) records() []adapterkit.OpRecord {
59		out := make([]adapterkit.OpRecord, 0, len(e.ops))
60		for _, op := range e.ops {
61			out = append(out, adapterkit.OpRecord{Op: op.OpKind(), Path: op.OpPath()})
62		}
63		return out
64	}
65	
66	// wireOps marshals each accumulated op to its wire envelope for
67	// EmitResult.Ops, in the same order as records(). This carries the op
68	// content to the CLI core, which performs the actual writes
69	// (invariant #2). Decoded caller-side via contract.DecodeOp.
70	func (e *emittedOps) wireOps() ([]json.RawMessage, error) {
71		out := make([]json.RawMessage, 0, len(e.ops))
72		for _, op := range e.ops {
73			raw, err := json.Marshal(op)
74			if err != nil {
75				return nil, fmt.Errorf("claude: marshal op %s %q: %w", op.OpKind(), op.OpPath(), err)
76			}
77			out = append(out, raw)
78		}
79		return out, nil
80	}
81	
82	// handleEmit is the OnEmit handler the bundled adapter registers.
83	// Decodes the IR document, dispatches each node by kind, and returns
84	// the accumulated OpRecord summary.
85	//
86	// One-failed-node-fails-the-emit is the v1 behavior: if any node
87	// produces an error, the whole call returns that error and partially
88	// emitted ops are discarded. Per-node skip-with-warning is a Unit 8b
89	// extension.
90	//
91	// Context is checked between nodes so a runtime cancel during a
92	// large IR is honored without waiting for the full iteration.
93	func handleEmit(ctx context.Context, params adapterkit.EmitParams) (adapterkit.EmitResult, error) {
94		doc, err := decodeIRDocument(params.IR)
95		if err != nil {
96			return adapterkit.EmitResult{}, &adapterkit.Error{
97				Code:    adapterkit.CodeInvalidParams,
98				Message: fmt.Sprintf("claude: %s", err.Error()),
99			}
100		}
101	
102		// Detect duplicate (kind, id) pairs in the wire payload before
103		// emitting. The IR decoder enforces uniqueness on its own output
104		// but the wire shape can carry duplicates from a buggy or
105		// adversarial producer; emitting the same path twice would let
106		// the sync engine silently last-write-wins.
107		if err := rejectDuplicateNodes(doc.Nodes); err != nil {
108			return adapterkit.EmitResult{}, err
109		}
110	
111		emitted := &emittedOps{}
112	
113		// readmeEmitted dedups per-subdir mkdir+README pairs.
114		// sidecarEmitted dedups the .agent-sync-managed sidecar (only ever
115		// written next to .mcp.json; one per emit regardless of how many
116		// mcp-server-entry nodes are present).
117		state := emitState{
118			readmeEmitted:   map[string]bool{},
119			sidecarEmitted:  false,
120			emittedFilePath: map[string]struct{}{},
121		}
122	
123		// Iterate in a deterministic order (sorted by kind, then id) so
124		// op output is stable across runs and easy to compare against
125		// fixtures. The IR decoder upstream already sorts the same way,
126		// but we re-sort defensively in case a malformed decoder ships
127		// nodes in arbitrary order.
128		slices.SortFunc(doc.Nodes, func(a, b irNode) int {
129			if c := cmp.Compare(a.Kind, b.Kind); c != 0 {
130				return c
131			}
132			return cmp.Compare(a.ID, b.ID)
133		})
134	
135		for _, node := range doc.Nodes {
136			if err := ctx.Err(); err != nil {
137				return adapterkit.EmitResult{}, &adapterkit.Error{
138					Code:    adapterkit.CodeInternalError,
139					Message: fmt.Sprintf("claude: emit cancelled: %s", err.Error()),
140				}
141			}
142			if !nodeTargetsClaude(node) {
143				// Node is targeted at a different adapter — silent skip.
144				continue
145			}
146			if err := dispatchNode(emitted, node, &state); err != nil {
147				return adapterkit.EmitResult{}, err
148			}
149		}
150	
151		wire, err := emitted.wireOps()
152		if err != nil {
153			return adapterkit.EmitResult{}, &adapterkit.Error{
154				Code:    adapterkit.CodeInternalError,
155				Message: err.Error(),
156			}
157		}
158		return adapterkit.EmitResult{OpsPerformed: emitted.records(), Ops: wire}, nil
159	}
160	
161	// emitState carries per-emit dedup tables. Threading one struct
162	// instead of multiple maps keeps dispatchNode's signature stable as
163	// new dedup keys appear.
164	//
165	// emittedFilePath records every workspace-relative path that's been
166	// emitted as a write_file in this call. When two ops would target
167	// the same path (duplicate skill assets, asset RelPath colliding
168	// with the reserved README.md inside a per-skill folder, etc.) the
169	// dispatcher fails closed instead of letting the sync engine
170	// last-write-wins.
171	type emitState struct {
172		readmeEmitted   map[string]bool
173		sidecarEmitted  bool
174		emittedFilePath map[string]struct{}
175	}
176	
177	// recordWritePath registers a write_file path in the per-emit dedup
178	// table. Returns an InvalidParams error when the path was already
179	// emitted earlier in this call. Callers should check before
180	// constructing the OpWriteFile so the error message can include
181	// node-level context.
182	func (s *emitState) recordWritePath(path string) error {
183		if _, exists := s.emittedFilePath[path]; exists {
184			return &adapterkit.Error{
185				Code:    adapterkit.CodeInvalidParams,
186				Message: fmt.Sprintf("claude: duplicate write_file path %q in single emit", path),
187			}
188		}
189		s.emittedFilePath[path] = struct{}{}
190		return nil
191	}
192	
193	// dispatchNode routes one IR node to its kind-specific emitter.
194	func dispatchNode(emitted *emittedOps, node irNode, state *emitState) error {
195		if !ir.IsValidID(node.ID) {
196			return &adapterkit.Error{
197				Code:    adapterkit.CodeInvalidParams,
198				Message: fmt.Sprintf("claude: invalid node id %q", node.ID),
199			}
200		}
201		switch ir.Kind(node.Kind) {
202		case ir.KindRule:
203			return emitRule(emitted, node, state)
204		case ir.KindCommand:
205			return emitCommand(emitted, node, state)
206		case ir.KindSkill:
207			return emitSkill(emitted, node, state)
208		case ir.KindMCPServerEntry:
209			return emitMCPServerEntry(emitted, node, state)
210		case ir.KindAgentsMD:
211			return emitAgentsMD(emitted, node)
212		case ir.KindPluginReference:
213			return emitPluginReferenceWarning(emitted, node)
214		default:
215			return &adapterkit.Error{
216				Code:    adapterkit.CodeInvalidParams,
217				Message: fmt.Sprintf("claude: unknown IR kind %q for node %q", node.Kind, node.ID),
218			}
219		}
220	}
221	
222	// decodeIRDocument unmarshals the EmitParams.IR raw message. Returns
223	// a wrapped error on parse failure so handleEmit can convert it to a
224	// JSON-RPC InvalidParams response.
225	func decodeIRDocument(raw json.RawMessage) (irDocument, error) {
226		if len(raw) == 0 {
227			return irDocument{}, nil
228		}
229		var doc irDocument
230		if err := json.Unmarshal(raw, &doc); err != nil {
231			return irDocument{}, fmt.Errorf("decode IR document: %w", err)
232		}
233		return doc, nil
234	}
235	
236	// nodeTargetsClaude reports whether the node's targets list either
237	// is empty (means "all adapters") or includes the claude adapter.
238	// IR-side validation guarantees the contained values are known
239	// adapter names; we don't re-validate here.
240	func nodeTargetsClaude(node irNode) bool {
241		if len(node.Targets) == 0 {
242			return true
243		}
244		for _, t := range node.Targets {
245			if t == adapterName {
246				return true
247			}
248		}
249		return false
250	}
251	
252	// rejectDuplicateNodes returns InvalidParams when the wire payload
253	// contains two or more nodes with the same (kind, id) pair. The
254	// fail-closed default avoids the silent last-write-wins behavior the
255	// sync engine would otherwise hit at write time.
256	func rejectDuplicateNodes(nodes []irNode) error {
257		seen := make(map[string]struct{}, len(nodes))
258		for _, n := range nodes {
259			key := n.Kind + "/" + n.ID
260			if _, dup := seen[key]; dup {
261				return &adapterkit.Error{
